final:
module RefModule (
    input wire clk,
    input wire rst,
    output reg [2:0] gray_out
);

    reg [2:0] unused_binary_count;

    always @(posedge clk or posedge rst) begin
        if (rst)
            unused_binary_count <= 3'b000;
        else
            unused_binary_count <= unused_binary_count + 1;
    end

    always @(*) begin
        gray_out = unused_binary_count ^ (unused_binary_count >> 1);
    end

endmodule
